#include <iostream>
using namespace std;

template<typename T>
T maximum(T a, T b) {
 return (a > b) ? a : b;
}

int main() {
 cout << "Max(10, 20): " << maximum(10, 20) << endl;
 cout << "Max(3.14, 2.71): " << maximum(3.14, 2.71) << endl;
 cout << "Max('A', 'Z'): " << maximum('A', 'Z') << endl;
 return 0;
}

#include <iostream>
using namespace std;

template<typename T1, typename T2>
class Pair {
private:
 T1 first;
 T2 second;
public:
 Pair(T1 a, T2 b) : first(a), second(b) {}
 T1 getFirst() const { return first; }
 T2 getSecond() const { return second; }
};

int main() {
 Pair<int, string> p1(1, "One");
 Pair<double, char> p2(3.14, 'A');
 cout << p1.getFirst() << ": " << p1.getSecond() << endl;
 cout << p2.getFirst() << ": " << p2.getSecond() << endl;
 return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
 vector<int> v;

 // Adding elements
 v.push_back(50);
 v.push_back(30);
 v.push_back(70);
 v.push_back(20);

 cout << "Initial: ";
 for(int x : v) cout << x << " ";
 cout << endl;

 // Sort
 sort(v.begin(), v.end());
 cout << "Sorted: ";
 for(int x : v) cout << x << " ";
 cout << endl;

 // Find
 auto it = find(v.begin(), v.end(), 30);
 if(it != v.end())
 cout << "Found at index: " << (it - v.begin()) << endl;

 // Size and capacity
 cout << "Size: " << v.size() << ", Capacity: " << v.capacity() << endl;

 return 0;
}

#include <iostream>
#include <map>
using namespace std;

int main() {
 map<string, int> ages;

 ages["Alice"] = 25;
 ages["Bob"] = 30;
 ages["Charlie"] = 35;

 // Iterator traversal (sorted by key)
 cout << "Sorted map entries:\n";
 for(auto it = ages.begin(); it != ages.end(); ++it) {
 cout << it->first << ": " << it->second << endl;
 }

 // Find by key
 auto it = ages.find("Bob");
 if(it != ages.end()) {
 cout << "Found: " << it->first << " = " << it->second << endl;
 }

 return 0;
}

#include <iostream>
using namespace std;

// Primary template
template<typename T>
class Container {
public:
 void display() { cout << "Generic: " << typeid(T).name() << endl; }
};

// Full specialization for int
template<>
class Container<int> {
public:
 void display() { cout << "Specialized for int" << endl; }
};

// Partial specialization for pointers
template<typename T>
class Container<T*> {
public:
 void display() { cout << "Specialized for pointers" << endl; }
};

int main() {
 Container<double> c1; c1.display();
 Container<int> c2; c2.display();
 Container<string*> c3; c3.display();
 return 0;
}
